{
  "name": "django-graphql-explorer",
  "displayName": "Django GraphQL Explorer",
  "description": "Discover and navigate GraphQL schemas (Graphene, Strawberry, Ariadne, .graphql files) in your Django workspace",
  "version": "0.0.3",
  "publisher": "newdlops",
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "https://github.com/newdlops/django-graphql-extension"
  },
  "engines": {
    "vscode": "^1.75.0"
  },
  "categories": [
    "Programming Languages",
    "Linters",
    "Other"
  ],
  "keywords": [
    "django",
    "graphql",
    "graphene",
    "strawberry",
    "ariadne",
    "schema",
    "explorer",
    "codelens"
  ],
  "activationEvents": [
    "workspaceContains:**/settings.py",
    "workspaceContains:**/*.graphql",
    "workspaceContains:**/*.gql"
  ],
  "main": "./out/extension.js",
  "icon": "media/icon.png",
  "contributes": {
    "viewsContainers": {
      "activitybar": [
        {
          "id": "djangoGraphql",
          "title": "Django GraphQL",
          "icon": "media/graphql-activity.svg"
        }
      ]
    },
    "views": {
      "djangoGraphql": [
        {
          "id": "djangoGraphqlExplorer.view",
          "name": "Schema Explorer",
          "type": "webview"
        }
      ]
    },
    "configuration": {
      "title": "Django GraphQL Explorer",
      "properties": {
        "djangoGraphqlExplorer.inlayHints": {
          "type": "boolean",
          "default": false,
          "description": "Show inline `→ TypeName` chips after every gql field. Disabled by default in favor of the Live Query Graph (Beside panel)."
        }
      }
    },
    "commands": [
      {
        "command": "djangoGraphqlExplorer.refresh",
        "title": "Django GraphQL: Refresh Schema",
        "icon": "$(refresh)"
      },
      {
        "command": "djangoGraphqlExplorer.clearCache",
        "title": "Django GraphQL: Clear Parse Cache",
        "icon": "$(clear-all)"
      },
      {
        "command": "djangoGraphqlExplorer.inspectType",
        "title": "Django GraphQL: Inspect Type…",
        "icon": "$(search)"
      },
      {
        "command": "djangoGraphqlExplorer.openLiveInspector",
        "title": "Django GraphQL: Open Live Query Structure",
        "icon": "$(json)"
      }
    ],
    "menus": {
      "view/title": [
        {
          "command": "djangoGraphqlExplorer.openLiveInspector",
          "when": "view == djangoGraphqlExplorer.view",
          "group": "navigation@0"
        },
        {
          "command": "djangoGraphqlExplorer.inspectType",
          "when": "view == djangoGraphqlExplorer.view",
          "group": "navigation@1"
        },
        {
          "command": "djangoGraphqlExplorer.refresh",
          "when": "view == djangoGraphqlExplorer.view",
          "group": "navigation@2"
        },
        {
          "command": "djangoGraphqlExplorer.clearCache",
          "when": "view == djangoGraphqlExplorer.view",
          "group": "overflow@0"
        }
      ],
      "commandPalette": [
        {
          "command": "djangoGraphqlExplorer.refresh"
        },
        {
          "command": "djangoGraphqlExplorer.clearCache"
        },
        {
          "command": "djangoGraphqlExplorer.inspectType"
        },
        {
          "command": "djangoGraphqlExplorer.openLiveInspector"
        }
      ]
    }
  },
  "scripts": {
    "compile": "tsc -p ./",
    "watch": "tsc -watch -p ./",
    "lint": "eslint src --ext ts",
    "test": "vitest run",
    "test:watch": "vitest",
    "compile:e2e": "tsc -p ./tsconfig.e2e.json",
    "pretest:e2e": "npm run compile && npm run compile:e2e",
    "test:e2e": "node out-e2e/runTests.js",
    "icons": "node scripts/generate-icon.mjs",
    "build:native": "cd native && npx napi build --release --platform",
    "build:native:debug": "cd native && npx napi build --platform",
    "build:all": "npm run build:native && npm run compile",
    "package": "npm run build:native && npm run compile && vsce package",
    "publish": "npm run build:native && npm run compile && vsce publish"
  },
  "devDependencies": {
    "@types/mocha": "^10.0.10",
    "@types/node": "^18.0.0",
    "@types/vscode": "^1.75.0",
    "@vscode/test-electron": "^2.5.2",
    "glob": "^10.5.0",
    "mocha": "^11.7.5",
    "typescript": "^5.3.0",
    "vitest": "^1.6.1"
  }
}
